SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

CREATE OR REPLACE VIEW view_tge_dep_coll_head (membership_no, loan_contract_no, loan_approve_amount, principal_balance, begining_of_contract, count_return, deposit_account_no, deposit_balance, last_withdraw_date, share_stock, share_begin, withdrawed_amt, withdrawable_amt, loan_type_desc) AS select MEMBERSHIP_NO, LOAN_CONTRACT_NO, LOAN_APPROVE_AMOUNT, PRINCIPAL_BALANCE, BEGINING_OF_CONTRACT, COUNT_RETURN, DEPOSIT_ACCOUNT_NO, DEPOSIT_BALANCE, LAST_WITHDRAW_DATE, SHARE_STOCK, SHARE_BEGIN, WITHDRAWED_AMT
  , ( SHARE_STOCK - SHARE_BEGIN - WITHDRAWED_AMT ) as WITHDRAWABLE_AMT
  , LOAN_TYPE_DESC
  FROM
  ( 
  SELECT sc_lon_m_contract.membership_no,   
         sc_lon_m_contract.loan_contract_no,   
         sc_lon_m_contract.loan_approve_amount,   
         sc_lon_m_loan_card.principal_balance,   
         sc_lon_m_contract.begining_of_contract,  

         ( SELECT COUNT(1)
         FROM sc_kep_t_monthly_receive
         WHERE MEMBERSHIP_NO = sc_lon_m_contract.membership_no
         AND RECEIPT_DATE >= sc_lon_m_contract.begining_of_contract 
         AND RECEIPT_STATUS = '2' ) AS count_return ,

         sc_dep_m_creditor.deposit_account_no,   
         sc_dep_m_creditor.deposit_balance,  

         (  SELECT  MAX( sc_dep_m_creditor_item.operate_date  )
            FROM sc_dep_m_creditor_item,   
            sc_dep_m_ucf_dep_item_type  
            WHERE ( sc_dep_m_creditor_item.item_type = sc_dep_m_ucf_dep_item_type.deposit_item_type )   
            and ( sc_dep_m_ucf_dep_item_type.sign_flag = -1 )   
            and    sc_dep_m_creditor_item.operate_date >= sc_lon_m_contract.begining_of_contract 
            and ( sc_dep_m_creditor_item.deposit_account_no = sc_dep_m_creditor.deposit_account_no  )  ) AS last_withdraw_date ,

         sc_mem_m_share_mem.share_stock,   
         pka_com_function.fp_shr_get_balance_atdate(   sc_lon_m_contract.membership_no, sc_lon_m_contract.begining_of_contract ) as share_begin  

,coalesce( (   SELECT  sum( sc_dep_m_creditor_item.deposit_balance  )
     FROM sc_dep_m_creditor_item,   
         sc_dep_m_ucf_dep_item_type  
   WHERE ( sc_dep_m_creditor_item.item_type = sc_dep_m_ucf_dep_item_type.deposit_item_type )   
     and ( sc_dep_m_ucf_dep_item_type.sign_flag = -1 )   
    and    sc_dep_m_creditor_item.operate_date >= sc_lon_m_contract.begining_of_contract 
     and ( sc_dep_m_creditor_item.deposit_account_no = sc_dep_m_creditor.deposit_account_no  )  ),0)  as withdrawed_amt

,(select loan_type_description from sc_lon_m_rule where sc_lon_m_rule.loan_type = sc_lon_m_contract.loan_type ) as loan_type_desc
    FROM sc_lon_m_contract,   
         sc_lon_m_loan_card,   
         sc_mem_m_share_mem,   
         sc_dep_m_creditor  
   WHERE ( sc_lon_m_contract.loan_contract_no = sc_lon_m_loan_card.loan_contract_no ) and ( sc_lon_m_loan_card.membership_no = sc_mem_m_share_mem.membership_no ) and ( sc_mem_m_share_mem.membership_no = sc_dep_m_creditor.membership_no ) and ( sc_lon_m_contract.loan_type = sc_dep_m_creditor.loan_type_coll ) and ( sc_dep_m_creditor.deposit_type_code in (  '61','62' ) )    
)
--AND   ( sc_lon_m_contract.loan_contract_no = 'ส000983/64' )
;

